{"version":3,"file":"ably-chat.js","sources":["../../src/core/logger.ts","../../src/core/config.ts","../../src/core/utils/event-emitter.ts","../../src/core/connection.ts","../../node_modules/dequal/dist/index.mjs","../../src/core/events.ts","../../src/core/message.ts","../../src/core/message-parser.ts","../../src/core/messages-reactions.ts","../../src/core/messages.ts","../../src/core/chat-api.ts","../../src/core/errors.ts","../../src/core/id.ts","../../node_modules/lodash.clonedeep/index.js","../../src/core/channel.ts","../../src/core/version.ts","../../src/core/channel-manager.ts","../../src/core/occupancy.ts","../../src/core/presence.ts","../../node_modules/async-mutex/index.mjs","../../src/core/room-status.ts","../../src/core/room-lifecycle-manager.ts","../../src/core/room-options.ts","../../src/core/reaction.ts","../../src/core/reaction-parser.ts","../../src/core/realtime.ts","../../src/core/room-reactions.ts","../../src/core/typing.ts","../../src/core/room.ts","../../src/core/rooms.ts","../../src/core/chat.ts"],"sourcesContent":["import * as Ably from 'ably';¥n¥nimport { NormalizedChatClientOptions } from './config.js';¥n¥n/**¥n * Interface for loggers.¥n */¥nexport interface Logger {¥n  /**¥n   * Log a message at the trace level.¥n   * @param message The message to log.¥n   * @param context The context of the log message as key-value pairs.¥n   */¥n  trace(message: string, context?: LogContext): void;¥n¥n  /**¥n   * Log a message at the debug level.¥n   * @param message The message to log.¥n   * @param context The context of the log message as key-value pairs.¥n   */¥n  debug(message: string, context?: LogContext): void;¥n¥n  /**¥n   * Log a message at the info level.¥n   * @param message The message to log.¥n   * @param context The context of the log message as key-value pairs.¥n   */¥n  info(message: string, context?: LogContext): void;¥n¥n  /**¥n   * Log a message at the warn level.¥n   * @param message The message to log.¥n   * @param context The context of the log message as key-value pairs.¥n   */¥n  warn(message: string, context?: LogContext): void;¥n¥n  /**¥n   * Log a message at the error level.¥n   * @param message The message to log.¥n   * @param context The context of the log message as key-value pairs.¥n   */¥n  error(message: string, context?: LogContext): void;¥n¥n  /**¥n   * Creates a new logger with a context that will be merged with any context provided to individual log calls.¥n   * The context will be overridden by any matching keys in the individual log call's context.¥n   * @param context The context to use for all log calls.¥n   * @returns A new logger instance with the context.¥n   */¥n  withContext(context: LogContext): Logger;¥n}¥n¥n/**¥n * Represents the different levels of logging that can be used.¥n */¥nexport enum LogLevel {¥n  /**¥n   * Something routine and expected has occurred. This level will provide logs for the vast majority of operations¥n   * and function calls.¥n   */¥n  Trace = 'trace',¥n¥n  /**¥n   * Development information, messages that are useful when trying to debug library behavior,¥n   * but superfluous to normal operation.¥n   */¥n  Debug = 'debug',¥n¥n  /**¥n   * Informational messages. Operationally significant to the library but not out of the ordinary.¥n   */¥n  Info = 'info',¥n¥n  /**¥n   * Anything that is not immediately an error, but could cause unexpected behavior in the future. For example,¥n   * passing an invalid value to an option. Indicates that some action should be taken to prevent future errors.¥n   */¥n  Warn = 'warn',¥n¥n  /**¥n   * A given operation has failed and cannot be automatically recovered. The error may threaten the continuity¥n   * of operation.¥n   */¥n  Error = 'error',¥n¥n  /**¥n   * No logging will be performed.¥n   */¥n  Silent = 'silent',¥n}¥n¥n/**¥n * Represents the context of a log message.¥n * It is an object of key-value pairs that can be used to provide additional context to a log message.¥n */¥n// eslint-disable-next-line @typescript-eslint/no-explicit-any¥nexport type LogContext = Record<string, any>;¥n¥n/**¥n * A function that can be used to handle log messages.¥n * @param message The message to log.¥n * @param level The log level of the message.¥n * @param context The context of the log message as key-value pairs.¥n */¥nexport type LogHandler = (message: string, level: LogLevel, context?: LogContext) => void;¥n¥n/**¥n * A simple console logger that logs messages to the console.¥n *¥n * @param message The message to log.¥n * @param level The log level of the message.¥n * @param context - The context of the log message as key-value pairs.¥n */¥nconst consoleLogger = (message: string, level: LogLevel, context?: LogContext) => {¥n  const contextString = context ? `, context: ${JSON.stringify(context)}` : '';¥n  const formattedMessage = `[${new Date().toISOString()}] ${level.valueOf().toUpperCase()} ably-chat: ${message}${contextString}`;¥n¥n  switch (level) {¥n    case LogLevel.Trace:¥n    case LogLevel.Debug: {¥n      console.log(formattedMessage);¥n      break;¥n    }¥n    case LogLevel.Info: {¥n      console.info(formattedMessage);¥n      break;¥n    }¥n    case LogLevel.Warn: {¥n      console.warn(formattedMessage);¥n      break;¥n    }¥n    case LogLevel.Error: {¥n      console.error(formattedMessage);¥n      break;¥n    }¥n    case LogLevel.Silent: {¥n      break;¥n    }¥n  }¥n};¥n¥nexport const makeLogger = (options: NormalizedChatClientOptions): Logger => {¥n  const logHandler = options.logHandler ?? consoleLogger;¥n¥n  return new DefaultLogger(logHandler, options.logLevel);¥n};¥n¥n/**¥n * A convenient list of log levels as numbers that can be used for easier comparison.¥n */¥nenum LogLevelNumbers {¥n  Trace = 0,¥n  Debug = 1,¥n  Info = 2,¥n  Warn = 3,¥n  Error = 4,¥n  Silent = 5,¥n}¥n¥n/**¥n * A mapping of log levels to their numeric equivalents.¥n */¥nconst logLevelNumberMap = new Map<LogLevel, LogLevelNumbers>([¥n  [LogLevel.Trace, LogLevelNumbers.Trace],¥n  [LogLevel.Debug, LogLevelNumbers.Debug],¥n  [LogLevel.Info, LogLevelNumbers.Info],¥n  [LogLevel.Warn, LogLevelNumbers.Warn],¥n  [LogLevel.Error, LogLevelNumbers.Error],¥n  [LogLevel.Silent, LogLevelNumbers.Silent],¥n]);¥n¥n/**¥n * A default logger implementation.¥n */¥nclass DefaultLogger implements Logger {¥n  private readonly _handler: LogHandler;¥n  private readonly _levelNumber: LogLevelNumbers;¥n  private readonly _context?: LogContext;¥n¥n  constructor(handler: LogHandler, level: LogLevel, context?: LogContext) {¥n    this._handler = handler;¥n    this._context = context;¥n¥n    const levelNumber = logLevelNumberMap.get(level);¥n    if (levelNumber === undefined) {¥n      throw new Ably.ErrorInfo(`Invalid log level: ${level}`, 50000, 500);¥n    }¥n¥n    this._levelNumber = levelNumber;¥n  }¥n¥n  trace(message: string, context?: LogContext): void {¥n    this._write(message, LogLevel.Trace, LogLevelNumbers.Trace, context);¥n  }¥n¥n  debug(message: string, context?: LogContext): void {¥n    this._write(message, LogLevel.Debug, LogLevelNumbers.Debug, context);¥n  }¥n¥n  info(message: string, context?: LogContext): void {¥n    this._write(message, LogLevel.Info, LogLevelNumbers.Info, context);¥n  }¥n¥n  warn(message: string, context?: LogContext): void {¥n    this._write(message, LogLevel.Warn, LogLevelNumbers.Warn, context);¥n  }¥n¥n  error(message: string, context?: LogContext): void {¥n    this._write(message, LogLevel.Error, LogLevelNumbers.Error, context);¥n  }¥n¥n  withContext(context: LogContext): Logger {¥n    // Get the original log level by finding the key in logLevelNumberMap that matches this._levelNumber¥n    const originalLevel =¥n      [...logLevelNumberMap.entries()].find(([, value]) => value === this._levelNumber)?.[0] ?? LogLevel.Error;¥n¥n    return new DefaultLogger(this._handler, originalLevel, this._mergeContext(context));¥n  }¥n¥n  private _write(message: string, level: LogLevel, levelNumber: LogLevelNumbers, context?: LogContext): void {¥n    if (levelNumber >= this._levelNumber) {¥n      this._handler(message, level, this._mergeContext(context));¥n    }¥n  }¥n¥n  private _mergeContext(context?: LogContext): LogContext | undefined {¥n    if (!this._context) {¥n      return context ?? undefined;¥n    }¥n¥n    return context ? { ...this._context, ...context } : this._context;¥n  }¥n}¥n","import { LogHandler, LogLevel } from './logger.js';¥n¥n/**¥n * Configuration options for the chat client.¥n */¥nexport interface ChatClientOptions {¥n  /**¥n   * A custom log handler that will be used to log messages from the client.¥n   * @defaultValue The client will log messages to the console.¥n   */¥n  logHandler?: LogHandler;¥n¥n  /**¥n   * The minimum log level at which messages will be logged.¥n   * @defaultValue LogLevel.error¥n   */¥n  logLevel?: LogLevel;¥n}¥n¥n/**¥n * Default configuration options for the chat client.¥n */¥nconst defaultClientOptions = {¥n  logLevel: LogLevel.Error,¥n};¥n¥n/**¥n * This type is used to modify the properties of one type with the properties of another type and thus¥n * can be used to turn client options into normalized client options.¥n */¥ntype Modify<T, R> = Omit<T, keyof R> & R;¥n¥n/**¥n * These are the normalized client options, with default values filled in for any missing properties.¥n */¥nexport type NormalizedChatClientOptions = Modify<¥n  ChatClientOptions,¥n  {¥n    logLevel: LogLevel;¥n  }¥n>;¥n¥nexport const normalizeClientOptions = (options?: ChatClientOptions): NormalizedChatClientOptions => {¥n  options = options ?? {};¥n¥n  return {¥n    ...options,¥n    logLevel: options.logLevel ?? defaultClientOptions.logLevel,¥n  };¥n};¥n","import * as Ably from 'ably';¥n¥n/**¥n * This type represents a callback that can be registered with an EventEmitter.¥n *¥n * The EventsMap is an interface of event names to the types of the payloads of¥n * those events. For example:¥n *¥n *     interface MyEvents {¥n *         reaction: {emoji: string}¥n *     }¥n *¥n * There is no need to use this type directly, it is used for defining the¥n * InterfaceEventEmitter.¥n */¥ntype Callback<EventsMap> = (arg: EventsMap[keyof EventsMap]) => void;¥ntype CallbackSingle<K> = (arg: K) => void;¥n¥n/**¥n * This interface extends the Ably.EventEmitter interface to add a type-safe¥n * emit method as well as convert an EventsMap into the type parameters used by¥n * Ably.EventEmitter.¥n */¥ninterface InterfaceEventEmitter<EventsMap> extends Ably.EventEmitter<Callback<EventsMap>, void, keyof EventsMap> {¥n  emit<K extends keyof EventsMap>(event: K, arg: EventsMap[K]): void;¥n¥n  on<K extends keyof EventsMap>(event: K, callback: CallbackSingle<EventsMap[K]>): void;¥n  on<K1 extends keyof EventsMap, K2 extends keyof EventsMap>(¥n    events: [K1, K2],¥n    callback: CallbackSingle<EventsMap[K1] | EventsMap[K2]>,¥n  ): void;¥n  on<K1 extends keyof EventsMap, K2 extends keyof EventsMap, K3 extends keyof EventsMap>(¥n    events: [K1, K2, K3],¥n    callback: CallbackSingle<EventsMap[K1] | EventsMap[K2] | EventsMap[K3]>,¥n  ): void;¥n  on(events: (keyof EventsMap)[], callback: Callback<EventsMap>): void;¥n  on(callback: Callback<EventsMap>): void;¥n¥n  off<K extends keyof EventsMap>(event: K, listener: CallbackSingle<EventsMap[K]>): void;¥n  off(listener?: Callback<EventsMap>): void;¥n  off<K extends EventsMap[keyof EventsMap]>(listener: CallbackSingle<K>): void;¥n}¥n¥n/**¥n * This is a workaround for the fact that the EventEmitter constructor is only¥n * exported from the ably-js package for internal use by other Ably SDKs (like¥n * this one).¥n *¥n * It is a correctly-typed constructor for the ably-js EventEmitter.¥n *¥n * We do not export this directly because we prefer to export a class, which is¥n * what we normally expect EventEmitter to be.¥n */¥nconst InternalEventEmitter: new <EventsMap>() => InterfaceEventEmitter<EventsMap> = (¥n  Ably.Realtime as unknown as { EventEmitter: new <EventsMap>() => InterfaceEventEmitter<EventsMap> }¥n).EventEmitter;¥n¥n/**¥n * EventEmitter class based on the internal ably-js EventEmitter. It is¥n * different from the ably-js EventEmitter because it takes an EventsMap type¥n * parameter as opposed to the three type parameters required by¥n * {@link Ably.EventEmitter}.¥n *¥n * We find the EventsMap type parameter to be more convenient to use in this¥n * Chat SDK.¥n *¥n * The EventsMap is an interface of event names to the types of the payloads of¥n * those events. For example:¥n *¥n *     interface MyEvents {¥n *         reaction: {emoji: string}¥n *     }¥n *¥n * There is no need to use this type directly, it is used for defining the¥n * InterfaceEventEmitter.¥n */¥nclass EventEmitter<EventsMap> extends InternalEventEmitter<EventsMap> {}¥n¥nexport default EventEmitter;¥n¥n/**¥n * Creates a wrapper function that forwards all arguments to the provided function.¥n * @param fn The function to wrap¥n * @returns A new function with the same signature as the input function¥n */¥nexport const wrap = <Args extends unknown[], Return>(fn: (...args: Args) => Return): ((...args: Args) => Return) => {¥n  return (...args: Args) => fn(...args);¥n};¥n","import * as Ably from 'ably';¥n¥nimport { Logger } from './logger.js';¥nimport { StatusSubscription } from './subscription.js';¥nimport EventEmitter, { wrap } from './utils/event-emitter.js';¥n¥n/**¥n * Default timeout for transient states before we attempt to handle them as a state change.¥n */¥nconst TRANSIENT_TIMEOUT = 5000;¥n¥n/**¥n * The different states that the connection can be in through its lifecycle.¥n */¥nexport enum ConnectionStatus {¥n  /**¥n   * A temporary state for when the library is first initialized.¥n   */¥n  Initialized = 'initialized',¥n¥n  /**¥n   * The library is currently connecting to Ably.¥n   */¥n  Connecting = 'connecting',¥n¥n  /**¥n   * The library is currently connected to Ably.¥n   */¥n  Connected = 'connected',¥n¥n  /**¥n   * The library is currently disconnected from Ably, but will attempt to reconnect.¥n   */¥n  Disconnected = 'disconnected',¥n¥n  /**¥n   * The library is in an extended state of disconnection, but will attempt to reconnect.¥n   */¥n  Suspended = 'suspended',¥n¥n  /**¥n   * The library is currently disconnected from Ably and will not attempt to reconnect.¥n   */¥n  Failed = 'failed',¥n}¥n¥n/**¥n * Represents a change in the status of the connection.¥n */¥nexport interface ConnectionStatusChange {¥n  /**¥n   * The new status of the connection.¥n   */¥n  current: ConnectionStatus;¥n¥n  /**¥n   * The previous status of the connection.¥n   */¥n  previous: ConnectionStatus;¥n¥n  /**¥n   * An error that provides a reason why the connection has¥n   * entered the new status, if applicable.¥n   */¥n  error?: Ably.ErrorInfo;¥n¥n  /**¥n   * The time in milliseconds that the client will wait before attempting to reconnect.¥n   */¥n  retryIn?: number;¥n}¥n¥n/**¥n * A function that can be called when the connection status changes.¥n * @param change The change in status.¥n */¥nexport type ConnectionStatusListener = (change: ConnectionStatusChange) => void;¥n¥n/**¥n * Represents a connection to Ably.¥n */¥nexport interface Connection {¥n  /**¥n   * The current status of the connection.¥n   */¥n  get status(): ConnectionStatus;¥n¥n  /**¥n   * The current error, if any, that caused the connection to enter the current status.¥n   */¥n  get error(): Ably.ErrorInfo | undefined;¥n¥n  /**¥n   * Registers a listener that will be called whenever the connection status changes.¥n   * @param listener The function to call when the status changes.¥n   * @returns An object that can be used to unregister the listener.¥n   */¥n  onStatusChange(listener: ConnectionStatusListener): StatusSubscription;¥n¥n  /**¥n   * Removes all listeners that were added by the `onStatusChange` method.¥n   */¥n  offAllStatusChange(): void;¥n}¥n¥ntype ConnectionEventsMap = Record<ConnectionStatus, ConnectionStatusChange>;¥n¥n/**¥n * An implementation of the `Connection` interface.¥n * @internal¥n */¥nexport class DefaultConnection implements Connection {¥n  private _status: ConnectionStatus = ConnectionStatus.Initialized;¥n  private _error?: Ably.ErrorInfo;¥n  private readonly _connection: Ably.Connection;¥n  private readonly _logger: Logger;¥n  private _transientTimeout?: ReturnType<typeof setTimeout>;¥n  private _emitter = new EventEmitter<ConnectionEventsMap>();¥n¥n  /**¥n   * Constructs a new `DefaultConnection` instance.¥n   * @param ably The Ably Realtime client.¥n   * @param logger The logger to use.¥n   */¥n  constructor(ably: Ably.Realtime, logger: Logger) {¥n    this._logger = logger;¥n¥n    // Set our initial status and error¥n    this._status = this._mapAblyStatusToChat(ably.connection.state);¥n    this._error = ably.connection.errorReason;¥n¥n    // Listen for changes to the connection status¥n    this._connection = ably.connection;¥n    this._connection.on((change: Ably.ConnectionStateChange) => {¥n      const chatState = this._mapAblyStatusToChat(change.current);¥n      if (chatState === this._status) {¥n        return;¥n      }¥n¥n      const stateChange: ConnectionStatusChange = {¥n        current: chatState,¥n        previous: this._status,¥n        error: change.reason,¥n        retryIn: change.retryIn,¥n      };¥n¥n      // If we're in the disconnected state, assume it's transient and set a timeout to propagate the change¥n      if (chatState === ConnectionStatus.Disconnected && !this._transientTimeout) {¥n        this._transientTimeout = setTimeout(() => {¥n          this._onTransientDisconnectTimeout(stateChange);¥n        }, TRANSIENT_TIMEOUT);¥n        return;¥n      }¥n¥n      if (this._transientTimeout) {¥n        // If we're in the connecting state, or disconnected state, and we have a transient timeout, we should ignore it -¥n        // if we can reach connected in a reasonable time, we can assume the disconnect was transient and suppress the¥n        // change¥n        if (chatState === ConnectionStatus.Connecting || chatState === ConnectionStatus.Disconnected) {¥n          this._logger.debug('ignoring transient state due to transient disconnect timeout', stateChange);¥n          return;¥n        }¥n¥n        this._cancelTransientDisconnectTimeout();¥n      }¥n¥n      this._applyStatusChange(stateChange);¥n    });¥n  }¥n¥n  /**¥n   * @inheritdoc¥n   */¥n  get status(): ConnectionStatus {¥n    return this._status;¥n  }¥n¥n  /**¥n   * @inheritdoc¥n   */¥n  get error(): Ably.ErrorInfo | undefined {¥n    return this._error;¥n  }¥n¥n  /**¥n   * @inheritdoc¥n   */¥n  onStatusChange(listener: ConnectionStatusListener): StatusSubscription {¥n    const wrapped = wrap(listener);¥n    this._emitter.on(wrapped);¥n¥n    return {¥n      off: () => {¥n        this._emitter.off(wrapped);¥n      },¥n    };¥n  }¥n¥n  /**¥n   * @inheritdoc¥n   */¥n  offAllStatusChange(): void {¥n    this._emitter.off();¥n  }¥n¥n  private _applyStatusChange(change: ConnectionStatusChange): void {¥n    this._status = change.current;¥n    this._error = change.error;¥n    this._logger.info(`Connection state changed`, change);¥n    this._emitter.emit(change.current, change);¥n  }¥n¥n  private _mapAblyStatusToChat(status: Ably.ConnectionState): ConnectionStatus {¥n    switch (status) {¥n      case 'closing':¥n      case 'closed': {¥n        return ConnectionStatus.Failed;¥n      }¥n      default: {¥n        return status as ConnectionStatus;¥n      }¥n    }¥n  }¥n¥n  /**¥n   * Handles a transient disconnect timeout.¥n   *¥n   * @param statusChange The change in status.¥n   */¥n  private _onTransientDisconnectTimeout(statusChange: ConnectionStatusChange): void {¥n    this._logger.debug('transient disconnect timeout reached');¥n    this._cancelTransientDisconnectTimeout();¥n¥n    // When we apply the status change, we should apply whatever the current state is at the time¥n    this._applyStatusChange({¥n      ...statusChange,¥n      current: this._mapAblyStatusToChat(this._connection.state),¥n    });¥n  }¥n¥n  /**¥n   * Cancels the transient disconnect timeout.¥n   */¥n  private _cancelTransientDisconnectTimeout(): void {¥n    if (this._transientTimeout) {¥n      clearTimeout(this._transientTimeout);¥n      this._transientTimeout = undefined;¥n    }¥n  }¥n}¥n","var has = Object.prototype.hasOwnProperty;¥n¥nfunction find(iter, tar, key) {¥n¥tfor (key of iter.keys()) {¥n¥t¥tif (dequal(key, tar)) return key;¥n¥t}¥n}¥n¥nexport function dequal(foo, bar) {¥n¥tvar ctor, len, tmp;¥n¥tif (foo === bar) return true;¥n¥n¥tif (foo && bar && (ctor=foo.constructor) === bar.constructor) {¥n¥t¥tif (ctor === Date) return foo.getTime() === bar.getTime();¥n¥t¥tif (ctor === RegExp) return foo.toString() === bar.toString();¥n¥n¥t¥tif (ctor === Array) {¥n¥t¥t¥tif ((len=foo.length) === bar.length) {¥n¥t¥t¥t¥twhile (len-- && dequal(foo[len], bar[len]));¥n¥t¥t¥t}¥n¥t¥t¥treturn len === -1;¥n¥t¥t}¥n¥n¥t¥tif (ctor === Set) {¥n¥t¥t¥tif (foo.size !== bar.size) {¥n¥t¥t¥t¥treturn false;¥n¥t¥t¥t}¥n¥t¥t¥tfor (len of foo) {¥n¥t¥t¥t¥ttmp = len;¥n¥t¥t¥t¥tif (tmp && typeof tmp === 'object') {¥n¥t¥t¥t¥t¥ttmp = find(bar, tmp);¥n¥t¥t¥t¥t¥tif (!tmp) return false;¥n¥t¥t¥t¥t}¥n¥t¥t¥t¥tif (!bar.has(tmp)) return false;¥n¥t¥t¥t}¥n¥t¥t¥treturn true;¥n¥t¥t}¥n¥n¥t¥tif (ctor === Map) {¥n¥t¥t¥tif (foo.size !== bar.size) {¥n¥t¥t¥t¥treturn false;¥n¥t¥t¥t}¥n¥t¥t¥tfor (len of foo) {¥n¥t¥t¥t¥ttmp = len[0];¥n¥t¥t¥t¥tif (tmp && typeof tmp === 'object') {¥n¥t¥t¥t¥t¥ttmp = find(bar, tmp);¥n¥t¥t¥t¥t¥tif (!tmp) return false;¥n¥t¥t¥t¥t}¥n¥t¥t¥t¥tif (!dequal(len[1], bar.get(tmp))) {¥n¥t¥t¥t¥t¥treturn false;¥n¥t¥t¥t¥t}¥n¥t¥t¥t}¥n¥t¥t¥treturn true;¥n¥t¥t}¥n¥n¥t¥tif (ctor === ArrayBuffer) {¥n¥t¥t¥tfoo = new Uint8Array(foo);¥n¥t¥t¥tbar = new Uint8Array(bar);¥n¥t¥t} else if (ctor === DataView) {¥n¥t¥t¥tif ((len=foo.byteLength) === bar.byteLength) {¥n¥t¥t¥t¥twhile (len-- && foo.getInt8(len) === bar.getInt8(len));¥n¥t¥t¥t}¥n¥t¥t¥treturn len === -1;¥n¥t¥t}¥n¥n¥t¥tif (ArrayBuffer.isView(foo)) {¥n¥t¥t¥tif ((len=foo.byteLength) === bar.byteLength) {¥n¥t¥t¥t¥twhile (len-- && foo[len] === bar[len]);¥n¥t¥t¥t}¥n¥t¥t¥treturn len === -1;¥n¥t¥t}¥n¥n¥t¥tif (!ctor || typeof foo === 'object') {¥n¥t¥t¥tlen = 0;¥n¥t¥t¥tfor (ctor in foo) {¥n¥t¥t¥t¥tif (has.call(foo, ctor) && ++len && !has.call(bar, ctor)) return false;¥n¥t¥t¥t¥tif (!(ctor in bar) || !dequal(foo[ctor], bar[ctor])) return false;¥n¥t¥t¥t}¥n¥t¥t¥treturn Object.keys(bar).length === len;¥n¥t¥t}¥n¥t}¥n¥n¥treturn foo !== foo && bar !== bar;¥n}¥n","import * as Ably from 'ably';¥n¥nimport { Message } from './message.js';¥n¥n/**¥n * All chat message events.¥n */¥nexport enum MessageEvents {¥n  /** Fires when a new chat message is received. */¥n  Created = 'message.created',¥n¥n  /** Fires when a chat message is updated. */¥n  Updated = 'message.updated',¥n¥n  /** Fires when a chat message is deleted. */¥n  Deleted = 'message.deleted',¥n}¥n¥n/**¥n * Realtime chat message names.¥n */¥nexport enum RealtimeMessageNames {¥n  /** Represents a regular chat message. */¥n  ChatMessage = 'chat.message',¥n}¥n¥n/**¥n * Chat Message Actions.¥n */¥nexport enum ChatMessageActions {¥n  /** Action applied to a new message. */¥n  MessageCreate = 'message.create',¥n¥n  /** Action applied to an updated message. */¥n  MessageUpdate = 'message.update',¥n¥n  /** Action applied to a deleted message. */¥n  MessageDelete = 'message.delete',¥n¥n  /** Action applied to an annotation summary message. */¥n  MessageAnnotationSummary = 'message.summary',¥n¥n  /** Action applied to a meta occupancy message. */¥n  MessageMetaOccupancy = 'meta.occupancy',¥n}¥n¥n/**¥n * Enum representing presence events.¥n */¥nexport enum PresenceEvents {¥n  /**¥n   * Event triggered when a user enters.¥n   */¥n  Enter = 'enter',¥n¥n  /**¥n   * Event triggered when a user leaves.¥n   */¥n  Leave = 'leave',¥n¥n  /**¥n   * Event triggered when a user updates their presence data.¥n   */¥n  Update = 'update',¥n  /**¥n   * Event triggered when a user initially subscribes to presence.¥n   */¥n  Present = 'present',¥n}¥n¥n/**¥n * Enum representing the typing event types.¥n */¥nexport enum TypingE