que: {},¥n    distinct: {},¥n    multiple: {},¥n  };¥n}¥n","import * as Ably from 'ably';¥n¥nimport { ChatMessageActions } from './events.js';¥nimport {¥n  DefaultMessage,¥n  emptyMessageReactions,¥n  Message,¥n  MessageHeaders,¥n  MessageMetadata,¥n  Operation,¥n} from './message.js';¥n¥ninterface MessagePayload {¥n  data?: {¥n    text?: string;¥n    metadata?: MessageMetadata;¥n  };¥n  clientId?: string;¥n  timestamp: number;¥n  extras?: {¥n    headers?: MessageHeaders;¥n  };¥n¥n  serial: string;¥n  createdAt: number;¥n  version: string;¥n  action: Ably.MessageAction;¥n  operation?: Ably.Operation;¥n}¥n¥n// Parse a realtime message to a chat message¥nexport function parseMessage(roomId: string | undefined, inboundMessage: Ably.InboundMessage): Message {¥n  const message = inboundMessage as MessagePayload;¥n¥n  if (!roomId) {¥n    throw new Ably.ErrorInfo(`received incoming message without roomId`, 50000, 500);¥n  }¥n¥n  if (!message.data) {¥n    throw new Ably.ErrorInfo(`received incoming message without data`, 50000, 500);¥n  }¥n¥n  if (!message.clientId) {¥n    throw new Ably.ErrorInfo(`received incoming message without clientId`, 50000, 500);¥n  }¥n¥n  if (message.data.text === undefined) {¥n    throw new Ably.ErrorInfo(`received incoming message without text`, 50000, 500);¥n  }¥n¥n  if (!message.extras) {¥n    throw new Ably.ErrorInfo(`received incoming message without extras`, 50000, 500);¥n  }¥n¥n  if (!message.serial) {¥n    throw new Ably.ErrorInfo(`received incoming message without serial`, 50000, 500);¥n  }¥n¥n  if (!message.version) {¥n    throw new Ably.ErrorInfo(`received incoming message without version`, 50000, 500);¥n  }¥n¥n  if (!message.createdAt) {¥n    throw new Ably.ErrorInfo(`received incoming message without createdAt`, 50000, 500);¥n  }¥n¥n  if (!message.timestamp) {¥n    throw new Ably.ErrorInfo(`received incoming message without timestamp`, 50000, 500);¥n  }¥n¥n  switch (message.action) {¥n    case ChatMessageActions.MessageCreate:¥n    case ChatMessageActions.MessageUpdate:¥n    case ChatMessageActions.MessageDelete: {¥n      break;¥n    }¥n    default: {¥n      throw new Ably.ErrorInfo(`received incoming message with unhandled action; ${message.action}`, 50000, 500);¥n    }¥n  }¥n  return new DefaultMessage({¥n    serial: message.serial,¥n    clientId: message.clientId,¥n    roomId: roomId,¥n    text: message.data.text,¥n    metadata: message.data.metadata ?? {},¥n    headers: message.extras.headers ?? {},¥n    action: message.action as ChatMessageActions,¥n    version: message.version,¥n    createdAt: new Date(message.createdAt),¥n    timestamp: new Date(message.timestamp),¥n    reactions: emptyMessageReactions(),¥n    operation: message.operation as Operation,¥n  });¥n}¥n","import * as Ably from 'ably';¥n¥nimport { ChannelOptionsMerger } from './channel-manager.js';¥nimport {¥n  AddMessageReactionParams as APIAddMessageReactionParams,¥n  ChatApi,¥n  DeleteMessageReactionParams as APIDeleteMessageReactionParams,¥n} from './chat-api.js';¥nimport {¥n  ChatMessageActions,¥n  MessageReactionEvents,¥n  MessageReactionRawEvent,¥n  MessageReactionSummaryEvent,¥n  MessageReactionType,¥n} from './events.js';¥nimport { Logger } from './logger.js';¥nimport { InternalRoomOptions, MessageOptions } from './room-options.js';¥nimport { Subscription } from './subscription.js';¥nimport EventEmitter, { wrap } from './utils/event-emitter.js';¥n¥n/**¥n * A listener for summary message reaction events.¥n * @param event The message reaction summary event that was received. Use it¥n *   with {@link Message.with} to keep an up-to-date reaction count.¥n */¥nexport type MessageReactionListener = (event: MessageReactionSummaryEvent) => void;¥n¥n/**¥n * A listener for individual message reaction events.¥n * @param event The message reaction event that was received.¥n */¥nexport type MessageRawReactionListener = (event: MessageReactionRawEvent) => void;¥n¥n/**¥n * Parameters for adding a message reaction.¥n */¥nexport interface AddMessageReactionParams {¥n  /**¥n   * The reaction name to add; ie. the emoji.¥n   */¥n  name: string;¥n¥n  /**¥n   * The type of reaction, must be one of {@link MessageReactionType}.¥n   * If not set, the default type will be used which is configured in the {@link MessageOptions.defaultMessageReactionType} of the room.¥n   */¥n  type?: MessageReactionType;¥n¥n  /**¥n   * The count of the reaction for type {@link MessageReactionType.Multiple}.¥n   * Defaults to 1 if not set. Not supported for other reaction types.¥n   * @default 1¥n   */¥n  count?: number;¥n}¥n¥n/**¥n * Parameters for deleting a message reaction.¥n */¥nexport interface DeleteMessageReactionParams {¥n  /**¥n   * The reaction name to delete; ie. the emoji. Required for all reaction types¥n   * except {@link MessageReactionType.Unique}.¥n   */¥n  name?: string;¥n¥n  /**¥n   * The type of reaction, must be one of {@link MessageReactionType}.¥n   * If not set, the default type will be used which is configured in the {@link MessageOptions.defaultMessageReactionType} of the room.¥n   */¥n  type?: MessageReactionType;¥n}¥n¥n/**¥n * Add, delete, and subscribe to message reactions.¥n */¥nexport interface MessagesReactions {¥n  /**¥n   * Add a message reactions¥n   * @param message The message to react to.¥n   * @param params Describe the reaction to add.¥n   * @returns A promise that resolves when the reaction is added.¥n   */¥n  add(message: { serial: string }, params: AddMessageReactionParams): Promise<void>;¥n¥n  /**¥n   * Delete a message reaction¥n   * @param message The message to remove the reaction from.¥n   * @param params The type of reaction annotation and the specific reaction to remove. The reaction to remove is required for all types except {@link MessageReactionType.Unique}.¥n   * @returns A promise that resolves when the reaction is deleted.¥n   */¥n  delete(message: { serial: string }, params?: DeleteMessageReactionParams): Promise<void>;¥n¥n  /**¥n   * Subscribe to message reaction summaries. Use this to keep message reaction¥n   * counts up to date efficiently in the UI.¥n   * @param listener The listener to call when a message reaction summary is received.¥n   * @returns A subscription object that should be used to unsubscribe.¥n   */¥n  subscribe(listener: MessageReactionListener): Subscription;¥n¥n  /**¥n   * Subscribe to individual reaction events.¥n   * @remarks If you only need to keep track of reaction counts and clients, use¥n   *  {@link subscribe} instead.¥n   * @param listener The listener to call when a message reaction event is received.¥n   * @returns A subscription object that should be used to unsubscribe.¥n   */¥n  subscribeRaw(listener: MessageRawReactionListener): Subscription;¥n}¥n¥n/**¥n * @inheritDoc¥n */¥nexport class DefaultMessageReactions implements MessagesReactions {¥n  private _emitter = new EventEmitter<{¥n    [MessageReactionEvents.Create]: MessageReactionRawEvent;¥n    [MessageReactionEvents.Delete]: MessageReactionRawEvent;¥n    [MessageReactionEvents.Summary]: MessageReactionSummaryEvent;¥n  }>();¥n¥n  private readonly _defaultType: MessageReactionType;¥n¥n  constructor(¥n    private readonly _logger: Logger,¥n    private readonly _options: MessageOptions | undefined,¥n    private readonly _api: ChatApi,¥n    private readonly _roomID: string,¥n    private readonly _channel: Ably.RealtimeChannel,¥n  ) {¥n    void _channel.subscribe(this._processMessageEvent.bind(this));¥n    if (this._options?.rawMessageReactions) {¥n      void _channel.annotations.subscribe(this._processAnnotationEvent.bind(this));¥n    }¥n    this._defaultType = this._options?.defaultMessageReactionType ?? MessageReactionType.Distinct;¥n  }¥n¥n  private _processAnnotationEvent(event: Ably.Annotation) {¥n    this._logger.trace('MessagesReactions._processAnnotationEvent();', { event });¥n¥n    if (!event.messageSerial) {¥n      this._logger.warn(¥n        'DefaultMessageReactions._processAnnotationEvent(); received event with missing messageSerial