y events¥n    if (event.action !== ChatMessageActions.MessageAnnotationSummary) {¥n      return;¥n    }¥n    if (!event.summary) {¥n      // This means the summary is now empty, which is valid.¥n      // Happens when there are no reactions such as after deleting the last reaction.¥n      event.summary = {};¥n    }¥n¥n    // they must have a serial¥n    if (!event.serial) {¥n      this._logger.warn('DefaultMessageReactions._processMessageEvent(); received summary without serial', {¥n        event,¥n      });¥n      return;¥n    }¥n¥n    const unique = (event.summary[MessageReactionType.Unique] ?? {}) as unknown as Ably.SummaryUniqueValues;¥n    const distinct = (event.summary[MessageReactionType.Distinct] ?? {}) as unknown as Ably.SummaryDistinctValues;¥n    const multiple = (event.summary[MessageReactionType.Multiple] ?? {}) as Ably.SummaryMultipleValues;¥n¥n    this._emitter.emit(MessageReactionEvents.Summary, {¥n      type: MessageReactionEvents.Summary,¥n      summary: {¥n        messageSerial: event.serial,¥n        unique: unique,¥n        distinct: distinct,¥n        multiple: multiple,¥n      },¥n    });¥n  }¥n¥n  /**¥n   * @inheritDoc¥n   */¥n  add(message: { serial: string }, params: AddMessageReactionParams): Promise<void> {¥n    this._logger.trace('MessagesReactions.add();', { message, params });¥n¥n    let { type, count } = params;¥n    if (!type) {¥n      type = this._defaultType;¥n    }¥n    if (type === MessageReactionType.Multiple && !count) {¥n      count = 1;¥n    }¥n    const apiParams: APIAddMessageReactionParams = { type, name: params.name };¥n    if (count) {¥n      apiParams.count = count;¥n    }¥n    return this._api.addMessageReaction(this._roomID, message.serial, apiParams);¥n  }¥n¥n  /**¥n   * @inheritDoc¥n   */¥n  delete(message: { serial: string }, params?: DeleteMessageReactionParams): Promise<void> {¥n    this._logger.trace('MessagesReactions.delete();', { message, params });¥n¥n    let type = params?.type;¥n    if (!type) {¥n      type = this._defaultType;¥n    }¥n    if (type !== MessageReactionType.Unique && !params?.name) {¥n      throw new Ably.ErrorInfo(`cannot delete reaction of type ${type} without a name`, 40001, 400);¥n    }¥n    const apiParams: APIDeleteMessageReactionParams = { type };¥n    if (type !== MessageReactionType.Unique) {¥n      apiParams.name = params?.name;¥n    }¥n    return this._api.deleteMessageReaction(this._roomID, message.serial, apiParams);¥n  }¥n¥n  /**¥n   * @inheritDoc¥n   */¥n  subscribe(listener: MessageReactionListener): Subscription {¥n    this._logger.trace('MessagesReactions.subscribe();');¥n¥n    const wrapped = wrap(listener);¥n    this._emitter.on(MessageReactionEvents.Summary, wrapped);¥n    return {¥n      unsubscribe: () => {¥n        this._emitter.off(wrapped);¥n      },¥n    };¥n  }¥n¥n  /**¥n   * @inheritDoc¥n   */¥n  subscribeRaw(listener: MessageRawReactionListener): Subscription {¥n    this._logger.trace('MessagesReactions.subscribeRaw();');¥n¥n    if (!this._options?.rawMessageReactions) {¥n      throw new Ably.ErrorInfo('Raw message reactions are not enabled', 40001, 400);¥n    }¥n    const wrapped = wrap(listener);¥n    this._emitter.on([MessageReactionEvents.Create, MessageReactionEvents.Delete], wrapped);¥n    return {¥n      unsubscribe: () => {¥n        this._emitter.off(wrapped);¥n      },¥n    };¥n  }¥n¥n  /**¥n   * Merges the channel options to add support for message reactions.¥n   *¥n   * @param roomOptions The room options to merge for.¥n   * @returns A function that merges the channel options for the room with the ones required for presence.¥n   */¥n  static channelOptionMerger(roomOptions: InternalRoomOptions): ChannelOptionsMerger {¥n    return (options) => {¥n      // annotation publish is always required for message reactions¥n      if (!options.modes.includes('ANNOTATION_PUBLISH')) {¥n        options.modes.push('ANNOTATION_PUBLISH');¥n      }¥n      // annotation subscribe is only required if the room has raw message reactions¥n      if (roomOptions.messages.rawMessageReactions && !options.modes.includes('ANNOTATION_SUBSCRIBE')) {¥n        options.modes.push('ANNOTATION_SUBSCRIBE');¥n      }¥n      return options;¥n    };¥n  }¥n}¥n","import * as Ably from 'ably';¥n¥nimport { ChatApi } from './chat-api.js';¥nimport { ChatMessageActions, MessageEvent, MessageEvents, RealtimeMessageNames } from './events.js';¥nimport { Logger } from './logger.js';¥nimport {¥n  DefaultMessage,¥n  emptyMessageReactions,¥n  Message,¥n  MessageHeaders,¥n  MessageMetadata,¥n  MessageOperationMetadata,¥n} from './message.js';¥nimport { parseMessage } from './message-parser.js';¥nimport { DefaultMessageReactions, MessagesReactions } from './messages-reactions.js';¥nimport { PaginatedResult } from './query.js';¥nimport { MessageOptions } from './room-options.js';¥nimport { Subscription } from './subscription.js';¥nimport EventEmitter, { wrap } from './utils/event-emitter.js';¥n¥n/**¥n * Event names and their respective payloads emitted by the messages feature.¥n */¥ninterface MessageEventsMap {¥n  [MessageEvents.Created]: MessageEvent;¥n  [MessageEvents.Updated]: MessageEvent;¥n  [MessageEvents.Deleted]: MessageEvent;¥n}¥n¥n/**¥n * Mapping of chat message actions to message events.¥n */¥nconst MessageActionsToEventsMap: Map<ChatMessageActions, MessageEvents> = new Map<ChatMessageActions, MessageEvents>([¥n  [ChatMessageActions.MessageCreate, MessageEvents.Created],¥n  [ChatMessageActions.MessageUpdate, MessageEvents.Updated],¥n  [ChatMessageActions.MessageDelete, MessageEvents.Deleted],¥n]);¥n¥n/**¥n * The order in which results should be returned when performing a paginated query (e.g. message history).¥n */¥nexport enum OrderBy {¥n  /**¥n   * Return results in ascending order (oldest first).¥n   */¥n  OldestFirst = 'oldestFirst',¥n¥n  /**¥n   * Return results in descending order (newest first).¥n   */¥n  NewestFirst = 'newestFirst',¥n}¥n¥n/**¥n * Options for querying messages in a chat room.¥n */¥nexport inter