setting custom styling like¥n   * background or text colors or fonts, adding links to external images,¥n   * emojis, etc.¥n   *¥n   * Do not use metadata for authoritative information. There is no server-side¥n   * validation. When reading the metadata, treat it like user input.¥n   *¥n   */¥n  metadata?: MessageMetadata;¥n¥n  /**¥n   * Optional headers of the message.¥n   *¥n   * The headers are a flat key-value map and are sent as part of the realtime¥n   * message's extras inside the `headers` property. They can serve similar¥n   * purposes as the metadata, but they are read by Ably and can be used for¥n   * features such as¥n   * [subscription filters](https://faqs.ably.com/subscription-filters).¥n   *¥n   * Do not use the headers for authoritative information. There is no¥n   * server-side validation. When reading the headers, treat them like user¥n   * input.¥n   *¥n   */¥n  headers?: MessageHeaders;¥n}¥n¥n/**¥n * A listener for message events in a chat room.¥n * @param event The message event that was received.¥n */¥nexport type MessageListener = (event: MessageEvent) => void;¥n¥n/**¥n * A response object that allows you to control a message subscription.¥n */¥nexport interface MessageSubscriptionResponse extends Subscription {¥n  /**¥n   * Get the previous messages that were sent to the room before the listener was subscribed.¥n   *¥n   * If the client experiences a discontinuity event (i.e. the connection was lost and could not be resumed), the starting point of¥n   * getPreviousMessages will be reset.¥n   *¥n   * Calls to getPreviousMessages will wait for continuity to be restored before resolving.¥n   *¥n   * Once continuity is restored, the subscription point will be set to the beginning of this new period of continuity. To¥n   * ensure that no messages are missed, you should call getPreviousMessages after any period of discontinuity to¥n   * fill any gaps in the message history.¥n   *¥n   * ```typescript¥n   * const { getPreviousMessages } = room.messages.subscribe(listener);¥n   * await getPreviousMessages({ limit: 10 });¥n   * ```¥n   *¥n   * @param params Options for the history query.¥n   * @returns A promise that resolves with the paginated result of messages, in newest-to-oldest order.¥n   */¥n  getPreviousMessages(params: Omit<QueryOptions, 'orderBy'>): Promise<PaginatedResult<Message>>;¥n}¥n¥n/**¥n * This interface is used to interact with messages in a chat room: subscribing¥n * to new messages, fetching history, or sending messages.¥n *¥n * Get an instance via {@link Room.messages}.¥n */¥nexport interface Messages {¥n  /**¥n   * Subscribe to new messages in this chat room.¥n   * @param listener callback that will be called¥n   * @returns A response object that allows you to control the subscription.¥n   */¥n  subscribe(listener: MessageListener): MessageSubscriptionResponse;¥n¥n  /**¥n   * Unsubscribe all listeners from new messages in the chat room.¥n   */¥n  unsubscribeAll(): void;¥n¥n  /**¥n   * Get messages that have been previously sent to the chat room, based on the provided options.¥n   *¥n   * @param options Options for the query.¥n   * @returns A promise that resolves with the paginated result of messages. This paginated result can¥n   * be used to fetch more messages if available.¥n   */¥n  get(options: QueryOptions): Promise<PaginatedResult<Message>>;¥n¥n  /**¥n   * Send a message in the chat room.¥n   *¥n   * This method uses the Ably Chat API endpoint for sending messages.¥n   *¥n   * Note that the Promise may resolve before OR after the message is received¥n   * from the realtime channel. This means you may see the message that was just¥n   * sent in a callback to `subscribe` before the returned promise resolves.¥n   *¥n   * @param params an object containing {text, headers, metadata} for the message¥n   * to be sent. Text is required, metadata and headers are optional.¥n   * @returns A promise that resolves when the message was published.¥n   */¥n  send(params: SendMessageParams): Promise<Message>;¥n¥n  /**¥n   * Delete a message in the chat room.¥n   *¥n   * This method uses the Ably Chat API REST endpoint for deleting messages.¥n   * It performs a `soft` delete, meaning the message is marked as deleted.¥n   *¥n   * Note that the Promise may resolve before OR after the message is deleted¥n   * from the realtime channel. This means you may see the message that was just¥n   * deleted in a callback to `subscribe` before the returned promise resolves.¥n   *¥n   * Should you wish to restore a deleted message, and providing you have the appropriate permissions,¥n   * you can simply send an update to the original message.¥n   * Note: This is subject to change in future versions, whereby a new permissions model will be introduced¥n   * and a deleted message may not be restorable in this way.¥n   *¥n   * @returns A promise that resolves when the message was deleted.¥n   * @param message - The message to delete.¥n   * @param deleteMessageParams - Optional details to record about the delete action.¥n   * @return A promise that resolves to the deleted message.¥n   */¥n  delete(message: Message, deleteMessageParams?: DeleteMessageParams): Promise<Message>;¥n¥n  /**¥n   * Update a message in the chat room.¥n   *¥n   * Note that the Promise may resolve before OR after the updated message is¥n   * received from the realtime channel. This means you may see the update that¥n   * was just sent in a callback to `subscribe` before the returned promise¥n   * resolves.¥n   *¥n   * @param message The message to update.¥n   * @param details Optional details to record about the update action.¥n   * @returns A promise of the updated message.¥n   */¥n  update(message: Message, details?: OperationDetails): Promise<Message>;¥n¥n  /**¥n   * Add, delete, and subscribe to message reactions.¥n   */¥n  reactions: MessagesReactions;¥n}¥n¥n/**¥n * @inheritDoc¥n */¥nexport class DefaultMessages implements Messages {¥n  private readonly _roomId: string;¥n  private readonly _options: MessageOptions;¥n  private readonly _channel: Ably.RealtimeChannel;¥n  private readonly _chatApi: ChatApi;¥n  private readonly _clientId: string;¥n  private readonly _listenerSubscriptionPoints: Map<¥n    MessageListener,¥n    Promise<{¥n      fromSerial: string;¥n    }>¥n  >;¥n  private readonly _logger: Logger;¥n  private readonly _emitter = new EventEmitter<MessageEventsMap>();¥n¥n  public readonly reactions: MessagesReactions;¥n¥n  /**¥n   * Constructs a new `DefaultMessages` instance.¥n   * @param roomId The unique identifier of the room.¥n   * @param channel An instance of the Realtime channel for the room.¥n   * @param chatApi An instance of the ChatApi.¥n   * @param clientId The client ID of the user.¥n   * @param logger An instance of the Logger.¥n   */¥n  constructor(¥n    roomId: string,¥n    options: MessageOptions,¥n    channel: Ably.RealtimeChannel,¥n    chatApi: ChatApi,¥n    clientId: string,¥n    logger: Logger,¥n  ) {¥n    this._roomId = roomId;¥n    this._options = options;¥n    this._channel = channel;¥n    this._chatApi = chatApi;¥n    this._clientId = clientId;¥n    this._logger = logger;¥n    this._listenerSubscriptionPoints = new Map<MessageListener, Promise<{ fromSerial: string }>>();¥n¥n    this.reactions = new DefaultMessageReactions(this._logger, options, this._chatApi, this._roomId, this._channel);¥n    this._applyChannelSubscriptions();¥n  }¥n¥n  /**¥n   * Sets up channel subscriptions for messages.¥n   */¥n  private _applyChannelSubscriptions(): void {¥n    // attachOnSubscribe is set to false in the default channel options, so this call cannot fail¥n    void this._channel.subscribe([RealtimeMessageNames.ChatMessage], this._processEvent.bind(this));¥n¥n    // Handles the case where channel attaches and resume state is false. This can happen when the channel is first attached,¥n    // or when the channel is reattached after a detach. In both cases, we reset the subscription points for all listeners.¥n    this._channel.on('attached', (message) => {¥n      this._handleAttach(message.resumed);¥n    });¥n¥n    // Handles the case where an update message is received from a channel after a detach and reattach.¥n    this._channel.on('update', (message) => {¥n      if (message.current === 'attached' && message.previous === 'attached') {¥n        this._handleAttach(message.resumed);¥n      }¥n    });¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  private async _getBeforeSubscriptionStart(¥n    listener: MessageListener,¥n    params: Omit<QueryOptions, 'orderBy'>,¥n  ): Promise<PaginatedResult<Message>> {¥n    this._logger.trace(`DefaultSubscriptionManager.getBeforeSubscriptionStart();`);¥n¥n    const subscriptionPoint = this._listenerSubscriptionPoints.get(listener);¥n¥n    if (subscriptionPoint === undefined) {¥n      this._logger.error(¥n        `DefaultSubscriptionManager.getBeforeSubscriptionStart(); listener has not been subscribed yet`,¥n      );¥n      throw new Ably.ErrorInfo(¥n        'cannot query history; listener has not been subscribed yet',¥n        40000,¥n        400,¥n      ) as unknown as Error;¥n    }¥n¥n    // Get the subscription point of the listener¥n    const subscriptionPointParams = await subscriptionPoint;¥n¥n    // Query messages from the subscription point to the start of the time window¥n    return this._chatApi.getMessages(this._roomId, {¥n      ...params,¥n      orderBy: OrderBy.NewestFirst,¥n      ...subscriptionPointParams,¥n    });¥n  }¥n¥n  /**¥n   * Handle the case where the channel experiences a detach and reattaches.¥n   */¥n  private _handleAttach(fromResume: boolean) {¥n    this._logger.trace(`DefaultSubscriptionManager.handleAttach();`);¥n¥n    // Do nothing if we have resumed as there is no discontinuity in the message stream¥n    if (fromResume) return;¥n¥n    // Reset subscription points for all listeners¥n    const newSubscriptionStartResolver = this._subscribeAtChannelAttach();¥n    for (const [listener] of this._listenerSubscriptionPoints.entries()) {¥n      this._listenerSubscriptionPoints.set(listener, newSubscriptionStartResolver);¥n    }¥n  }¥n¥n  /**¥n   * Create a promise that resolves with the attachSerial of the channel or the serial of the latest message.¥n   */¥n  private async _resolveSubscriptionStart(): Promise<{¥n    fromSerial: string;¥n  }> {¥n    const channelWithProperties = this._getChannelProperties();¥n¥n    // If we are attached, we can resolve with the channelSerial¥n    if (channelWithProperties.state === 'attached') {¥n      if (channelWithProperties.properties.channelSerial) {¥n        return { fromSerial: channelWithProperties.properties.channelSerial };¥n      }¥n      this._logger.error(`DefaultSubscriptionManager.handleAttach(); channelSerial is undefined`);¥n      throw new Ably.ErrorInfo('channel is attached, but channelSerial is not defined', 40000, 400) as unknown as Error;¥n    }¥n¥n    return this._subscribeAtChannelAttach();¥n  }¥n¥n  private _getChannelProperties(): Ably.RealtimeChannel & {¥n    properties: { attachSerial: string | undefined; channelSerial: string | undefined };¥n  } {¥n    // Get the attachSerial from the channel properties¥n    return this._channel as Ably.RealtimeChannel & {¥n      properties: {¥n        attachSerial: string | undefined;¥n        channelSerial: string | undefined;¥n      };¥n    };¥n  }¥n¥n  private async _subscribeAtChannelAttach(): Promise<{ fromSerial: string }> {¥n    const channelWithProperties = this._getChannelProperties();¥n    return new Promise((resolve, reject) => {¥n      // Check if the state is now attached¥n      if (channelWithProperties.state === 'attached') {¥n        // Get the attachSerial from the channel properties¥n        // AttachSerial should always be defined at this point, but we check just in case¥n        this._logger.debug('Messages._subscribeAtChannelAttach(); channel is attached already, using attachSerial', {¥n          attachSerial: channelWithProperties.properties.attachSerial,¥n        });¥n        if (channelWithProperties.properties.attachSerial) {¥n          resolve({ fromSerial: channelWithProperties.properties.attachSerial });¥n        } else {¥n          this._logger.error(`DefaultSubscriptionManager.handleAttach(); attachSerial is undefined`);¥n          reject(¥n            new Ably.ErrorInfo('channel is attached, but attachSerial is not defined', 40000, 400) as unknown as Error,¥n          );¥n        }¥n      }¥n¥n      channelWithProperties.once('attached', () => {¥n        // Get the attachSerial from the channel properties¥n        // AttachSerial should always be defined at this point, but we check just in case¥n        this._logger.debug('Messages._subscribeAtChannelAttach(); channel is now attached, using attachSerial', {¥n          attachSerial: channelWithProperties.properties.attachSerial,¥n        });¥n        if (channelWithProperties.properties.attachSerial) {¥n          resolve({ fromSerial: channelWithProperties.properties.attachSerial });¥n        } else {¥n          this._logger.error(`DefaultSubscriptionManager.handleAttach(); attachSerial is undefined`);¥n          reject(¥n            new Ably.ErrorInfo('channel is attached, but attachSerial is not defined', 40000, 400) as unknown as Error,¥n          );¥n        }¥n      });¥n    });¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  async get(options: QueryOptions): Promise<PaginatedResult<Message>> {¥n    this._logger.trace('Messages.query();');¥n    return this._chatApi.getMessages(this._roomId, options);¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  async send(params: SendMessageParams): Promise<Message> {¥n    this._logger.trace('Messages.send();', { params });¥n¥n    const { text, metadata, headers } = params;¥n¥n    const response = await this._chatApi.sendMessage(this._roomId, { text, headers, metadata });¥n    return new DefaultMessage({¥n      serial: response.serial,¥n      clientId: this._clientId,¥n      roomId: this._roomId,¥n      text: text,¥n      metadata: metadata ?? {},¥n      headers: headers ?? {},¥n      action: ChatMessageActions.MessageCreate,¥n      version: response.serial,¥n      createdAt: new Date(response.createdAt),¥n      timestamp: new Date(response.createdAt), // timestamp is the same as createdAt for new messages¥n      reactions: emptyMessageReactions(),¥n    });¥n  }¥n¥n  async update(message: Message, details?: OperationDetails): Promise<Message> {¥n    this._logger.trace('Messages.update();', { message, details });¥n¥n    const response = await this._chatApi.updateMessage(this._roomId, message.serial, {¥n      message: {¥n        text: message.text,¥n        metadata: message.metadata,¥n        headers: message.headers,¥n      },¥n      ...details,¥n    });¥n¥n    const updatedMessage: Message = new DefaultMessage({¥n      serial: message.serial,¥n      clientId: message.clientId,¥n      roomId: this._roomId,¥n      text: message.text,¥n      metadata: message.metadata,¥n      headers: message.headers,¥n      action: ChatMessageActions.MessageUpdate,¥n      version: response.version,¥n      createdAt: new Date(message.createdAt),¥n      timestamp: new Date(response.timestamp),¥n      reactions: emptyMessageReactions(),¥n      operation: {¥n        clientId: this._clientId,¥n        description: details?.description,¥n        metadata: details?.metadata,¥n      },¥n    });¥n¥n    this._logger.debug('Messages.update(); message update successfully', { message });¥n    return updatedMessage;¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  async delete(message: Message, params?: DeleteMessageParams): Promise<Message> {¥n    this._logger.trace('Messages.delete();', { params });¥n¥n    const response = await this._chatApi.deleteMessage(this._roomId, message.serial, params);¥n¥n    const deletedMessage: Message = new DefaultMessage({¥n      serial: message.serial,¥n      clientId: message.clientId,¥n      roomId: this._roomId,¥n      text: message.text,¥n      metadata: message.metadata,¥n      headers: message.headers,¥n      action: ChatMessageActions.MessageDelete,¥n      version: response.version,¥n      createdAt: new Date(message.createdAt),¥n      timestamp: new Date(response.timestamp),¥n      reactions: emptyMessageReactions(),¥n      operation: {¥n        clientId: this._clientId,¥n        description: params?.description,¥n        metadata: params?.metadata,¥n      },¥n    });¥n¥n    this._logger.debug('Messages.delete(); message deleted successfully', { deletedMessage });¥n    return deletedMessage;¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  subscribe(listener: MessageListener): MessageSubscriptionResponse {¥n    this._logger.trace('Messages.subscribe();');¥n    const wrapped = wrap(listener);¥n    this._emitter.on([MessageEvents.Created, MessageEvents.Updated, MessageEvents.Deleted], wrapped);¥n¥n    // Set the subscription point to a promise that resolves when the channel attaches or with the latest message¥n    const resolvedSubscriptionStart = this._resolveSubscriptionStart();¥n¥n    // Add a handler for unhandled rejections incase the room is released before the subscription point is resolved¥n    resolvedSubscriptionStart.catch(() => {¥n      this._logger.debug('Messages.subscribe(); subscription point was not resolved before the room was released');¥n    });¥n¥n    this._listenerSubscriptionPoints.set(wrapped, resolvedSubscriptionStart);¥n¥n    return {¥n      unsubscribe: () => {¥n        // Remove the wrapped listener from the subscription points¥n        this._listenerSubscriptionPoints.delete(wrapped);¥n        this._logger.trace('Messages.unsubscribe();');¥n        this._emitter.off(wrapped);¥n      },¥n      getPreviousMessages: (params: Omit<QueryOptions, 'orderBy'>) => this._getBeforeSubscriptionStart(wrapped, params),¥n    };¥n  }¥n¥n  /**¥n   * @inheritdoc Messages¥n   */¥n  unsubscribeAll(): void {¥n    this._logger.trace('Messages.unsubscribeAll();');¥n    this._emitter.off();¥n    this._listenerSubscriptionPoints.clear();¥n  }¥n¥n  private _processEvent(channelEventMessage: Ably.InboundMessage) {¥n    this._logger.trace('Messages._processEvent();', {¥n      channelEventMessage,¥n    });¥n    const { action } = channelEventMessage;¥n    const event = MessageActionsToEventsMap.get(action as ChatMessageActions);¥n    if (!event) {¥n      this._logger.debug('Messages._processEvent(); received unknown message action', { action });¥n      return;¥n    }¥n    // Send the message to the listeners¥n    const message = this._parseNewMessage(channelEventMessage);¥n    if (!message) {¥n      return;¥n    }¥n¥n    this._emitter.emit(event, { type: event, message: message });¥n  }¥n¥n  /**¥n   * Validate the realtime message and convert it to a chat message.¥n   */¥n  private _parseNewMessage(channelEventMessage: Ably.InboundMessage): Message | undefined {¥n    try {¥n      return parseMessage(this._roomId, channelEventMessage);¥n    } catch (error: unknown) {¥n      this._logger.error(`failed to parse incoming message;`, { channelEventMessage, error: error as Ably.ErrorInfo });¥n    }¥n  }¥n}¥n","import * as Ably from 'ably';¥n¥nimport { Logger } from './logger.js';¥nimport {¥n  DefaultMessage,¥n  emptyMessageReactions,¥n  Message,¥n  MessageHeaders,¥n  MessageMetadata,¥n  MessageOperationMetadata,¥n} from './message.js';¥nimport { OrderBy } from './messages.js';¥nimport { OccupancyEvent } from './occupancy.js';¥nimport { PaginatedResult } from './query.js';¥n¥nexport interface GetMessagesQueryParams {¥n  start?: number;¥n  end?: number;¥n  orderBy?: OrderBy;¥n  limit?: number;¥n  /**¥n   * Serial indicating the starting point for message retrieval.¥n   * This serial is specific to the region of the channel the client is connected to. Messages published within¥n   * the same region of the channel are guaranteed to be received in increasing serial order.¥n   *¥n   * @defaultValue undefined (not used if not specified)¥n   */¥n  fromSerial?: string;¥n}¥n¥n/**¥n * In the REST API, we currently use the `direction