ReactionParams {¥n  /**¥n   * The type of reaction, must be one of {@link MessageReactionType}.¥n   */¥n  type: string;¥n¥n  /**¥n   * The reaction name to remove, ie. the emoji. Required for all reaction types¥n   * except {@link MessageReactionType.Unique}.¥n   */¥n  name?: string;¥n}¥n¥n/**¥n * Chat SDK Backend¥n */¥nexport class ChatApi {¥n  private readonly _realtime: Ably.Realtime;¥n  private readonly _logger: Logger;¥n  private readonly _apiProtocolVersion: number = 3;¥n¥n  constructor(realtime: Ably.Realtime, logger: Logger) {¥n    this._realtime = realtime;¥n    this._logger = logger;¥n  }¥n¥n  async getMessages(roomId: string, params: GetMessagesQueryParams): Promise<PaginatedResult<Message>> {¥n    roomId = encodeURIComponent(roomId);¥n¥n    // convert the params into internal format¥n    const apiParams: ApiGetMessagesQueryParams = { ...params };¥n    if (params.orderBy) {¥n      switch (params.orderBy) {¥n        case OrderBy.NewestFirst: {¥n          apiParams.direction = 'backwards';¥n          break;¥n        }¥n        case OrderBy.OldestFirst: {¥n          apiParams.direction = 'forwards';¥n          break;¥n        }¥n        default: {¥n          // in vanilla JS use-cases, without types, we need to check non-enum values¥n          // eslint-disable-next-line @typescript-eslint/restrict-template-expressions¥n          throw new Ably.ErrorInfo(`invalid orderBy value: ${params.orderBy}`, 40000, 400);¥n        }¥n      }¥n    }¥n¥n    const data = await this._makeAuthorizedPaginatedRequest<Message>(`/chat/v3/rooms/${roomId}/messages`, apiParams);¥n    return this._recursivePaginateMessages(data);¥n  }¥n¥n  private _recursivePaginateMessages(data: PaginatedResult<Message>): PaginatedResult<Message> {¥n    const mapToDefaultMessage = (message: Message): DefaultMessage => {¥n      const metadata = message.metadata as MessageMetadata | undefined;¥n      const headers = message.headers as MessageHeaders | undefined;¥n      const reactions = message.reactions as typeof message.reactions | undefined;¥n¥n      return new DefaultMessage({¥n        ...message,¥n        metadata: metadata ?? {},¥n        headers: headers ?? {},¥n        createdAt: (message.createdAt as Date | undefined) ? new Date(message.createdAt) : new Date(message.timestamp),¥n        timestamp: new Date(message.timestamp),¥n        reactions: reactions ?? emptyMessageReactions(),¥n      });¥n    };¥n¥n    const paginatedResult: PaginatedResult<Message> = {} as PaginatedResult<Message>;¥n    paginatedResult.items = data.items.map((payload) => mapToDefaultMessage(payload));¥n¥n    // Recursively map the next paginated data¥n    paginatedResult.next = () =>¥n      data.next().then((nextData) => {¥n        // eslint-disable-next-line unicorn/no-null¥n        return nextData ? this._recursivePaginateMessages(nextData) : null;¥n      });¥n¥n    paginatedResult.first = () => data.first().then((firstData) => this._recursivePaginateMessages(firstData));¥n¥n    paginatedResult.current = () => data.current().then((currentData) => this._recursivePaginateMessages(currentData));¥n¥n    paginatedResult.hasNext = () => data.hasNext();¥n¥n    paginatedResult.isLast = () => data.isLast();¥n¥n    return { ...data, ...paginatedResult };¥n  }¥n¥n  deleteMessage(roomId: string, serial: string, params?: DeleteMessageParams): Promise<DeleteMessageResponse> {¥n    const body: { description?: string; metadata?: MessageOperationMetadata } = {¥n      description: params?.description,¥n      metadata: params?.metadata,¥n    };¥n    serial = encodeURIComponent(serial);¥n    roomId = encodeURIComponent(roomId);¥n    return this._makeAuthorizedRequest<DeleteMessageResponse>(¥n      `/chat/v3/rooms/${roomId}/messages/${serial}/delete`,¥n      'POST',¥n      body,¥n      {},¥n    );¥n  }¥n¥n  sendMessage(roomId: string, params: SendMessageParams): Promise<CreateMessageResponse> {¥n    const body: {¥n      text: string;¥n      metadata?: MessageMetadata;¥n      headers?: MessageHeade