geReactionType?: MessageReactionType;¥n}¥n¥n/**¥n * Represents the typing options for a chat room.¥n */¥nexport interface TypingOptions {¥n  /**¥n   * A throttle, in milliseconds, that enforces the minimum time interval between consecutive `typing.started`¥n   * events sent by the client to the server.¥n   * If typing.start() is called, the first call will emit an event immediately.¥n   * Later calls will no-op until the time has elapsed.¥n   * Calling typing.stop() will immediately send a `typing.stopped` event to the server and reset the interval,¥n   * allowing the client to send another `typing.started` event immediately.¥n   * @defaultValue 10000¥n   */¥n  heartbeatThrottleMs?: number;¥n}¥n¥n/**¥n * Represents the occupancy options for a chat room.¥n */¥nexport interface OccupancyOptions {¥n  /**¥n   * Whether to enable occupancy events.¥n   *¥n   * Note that enabling this feature will increase the number of messages received by the client as additional¥n   * messages will be sent by the server to indicate occupancy changes.¥n   *¥n   * @defaultValue false¥n   */¥n  enableEvents?: boolean;¥n}¥n¥n/**¥n * Represents the presence options for a chat room.¥n */¥nexport interface PresenceOptions {¥n  /**¥n   * Whether or not the client should receive presence events from the server. This setting¥n   * can be disabled if you are using presence in your Chat Room, but this particular client does not¥n   * need to receive the messages.¥n   *¥n   * @defaultValue true¥n   */¥n  enableEvents?: boolean;¥n}¥n¥n/**¥n * Represents the options for a given chat room.¥n */¥nexport interface RoomOptions {¥n  /**¥n   * The typing options for the room.¥n   */¥n  typing?: TypingOptions;¥n¥n  /**¥n   * The occupancy options for the room.¥n   */¥n  occupancy?: OccupancyOptions;¥n¥n  /**¥n   * The presence options for the room.¥n   */¥n  presence?: PresenceOptions;¥n¥n  /**¥n   * The message options for the room.¥n   */¥n  messages?: MessageOptions;¥n}¥n¥n/**¥n * Represents the normalized typing options for a chat room, which makes every property required.¥n */¥nexport type InternalTypingOptions = Required<TypingOptions>;¥n¥n/**¥n * Represents the normalized occupancy options for a chat room. Everything becomes required.¥n */¥nexport type InternalOccupancyOptions = Required<OccupancyOptions>;¥n¥n/**¥n * Represents the normalized presence options for a chat room. Everything becomes required.¥n */¥nexport type InternalPresenceOptions = Required<PresenceOptions>;¥n¥n/**¥n * Represents the normalized message options for a chat room. Everything becomes required.¥n */¥nexport type InternalMessageOptions = Required<MessageOptions>;¥n¥n/**¥n * Represents the normalized options for a chat room.¥n */¥nexport interface InternalRoomOptions {¥n  /**¥n   * Are we running the client in a React environment?¥n   */¥n  isReactClient: boolean;¥n¥n  /**¥n   * Typing options with everything made mandatory.¥n   */¥n  typing: InternalTypingOptions;¥n¥n  /**¥n   * Occupancy options with everything made mandatory.¥n   */¥n  occupancy: InternalOccupancyOptions;¥n¥n  /**¥n   * Presence options with everything made mandatory.¥n   */¥n  presence: InternalPresenceOptions;¥n¥n  /**¥n   * Message options with everything made mandatory.¥n   */¥n  messages: InternalMessageOptions;¥n}¥n¥n/**¥n * Creates an {@link ErrorInfo} for invalid room configuration.¥n *¥n * @param reason The reason for the invalid room configuration.¥n * @returns An ErrorInfo.¥n */¥nconst invalidRoomConfiguration = (reason: string): Error =>¥n  new Ably.ErrorInfo(`invalid room configuration: ${reason}`, 40001, 400);¥n¥nexport const validateRoomOptions = (options: InternalRoomOptions): void => {¥n  validateTypingOptions(options.typing);¥n};¥n¥nconst validateTypingOptions = (options: InternalTypingOptions): void => {¥n  if (options.heartbeatThrottleMs <= 0) {¥n    throw invalidRoomConfiguration('typing heartbeat interval must be greater than 0');¥n  }¥n};¥n¥nconst normalizeTypingOptions = (options: RoomOptions | undefined): InternalTypingOptions => {¥n  return {¥n    ...DefaultRoomOptions.typing,¥n    ...options?.typing,¥n  };¥n};¥n¥nconst normalizeOccupancyOptions = (options: RoomOptions | undefined): InternalOccupancyOptions => {¥n  return {¥n    ...DefaultRoomOptions.occupancy,¥n    ...options?.occupancy,¥n  };¥n};¥n¥nconst normalizePresenceOptions = (options: RoomOptions | undefined): InternalPresenceOptions => {¥n  return {¥n    ...DefaultRoomOptions.presence,¥n    ...options?.presence,¥n  };¥n};¥n¥nconst normalizeMessageOptions = (options: RoomOptions | undefined): InternalMessageOptions => {¥n  return {¥n    ...DefaultRoomOptions.messages,¥n    ...options?.messages,¥n  };¥n};¥n¥nexport const normalizeRoomOptions = (options: RoomOptions | undefined, react: boolean): InternalRoomOptions => {¥n  return {¥n    typing: normalizeTypingOptions(options),¥n    occupancy: normalizeOccupancyOptions(options),¥n    presence: normalizePresenceOptions(options),¥n    messages: normalizeMessageOptions(options),¥n    isReactClient: react,¥n  };¥n};¥n","import { Headers } from './headers.js';¥nimport { Metadata } from './metadata.js';¥n¥n/**¥n * {@link Headers} type for chat messages.¥n */¥nexport type ReactionHeaders = Headers;¥n¥n/**¥n * {@link Metadata} type for chat messages.¥n */¥nexport type ReactionMetadata = Metadata;¥n¥n/**¥n * Represents a room-level reaction.¥n */¥nexport interface Reaction {¥n  /**¥n   * The type of the reaction, for example ¥"like¥" or ¥"love¥".¥n   */¥n  readonly type: string;¥n¥n  /**¥n   * Metadata of the reaction. If no metadata was set this is an empty object.¥n   */¥n  readonly metadata: ReactionMetadata;¥n¥n  /**¥n   * Headers of the reaction. If no headers were set this is an empty object.¥n   */¥n  readonly headers: ReactionHeaders;¥n¥n  /**¥n   * The timestamp at which the reaction was sent.¥n   */¥n  readonly createdAt: Date;¥n¥n  /**¥n   * The clientId of the user who sent the reaction.¥n   */¥n  readonly clientId: string;¥n¥n  /**¥n   * Wheth