age.extras?.headers ?? {},¥n  );¥n}¥n","import * as Ably from 'ably';¥n¥n/**¥n * Convenience function that takes an event name and optional data and turns it into a¥n * message that the server will recognize as ephemeral.¥n *¥n * @param name The name of the event.¥n * @param data Optional data to send with the event.¥n * @returns An Ably message.¥n */¥nexport const ephemeralMessage = (name: string, data?: unknown): Ably.Message => {¥n  return {¥n    name: name,¥n    data: data,¥n    extras: {¥n      ephemeral: true,¥n    },¥n  };¥n};¥n¥n/**¥n * Takes an existing Ably message and converts it to an ephemeral message by adding¥n * the ephemeral flag in the extras field.¥n *¥n * @param message The Ably message to convert.¥n * @returns A new Ably message with the ephemeral flag set.¥n */¥nexport const messageToEphemeral = (message: Ably.Message): Ably.Message => {¥n  const extras = message.extras ? (message.extras as object) : {};¥n¥n  return {¥n    ...message,¥n    extras: {¥n      ...extras,¥n      ephemeral: true,¥n    },¥n  };¥n};¥n","import * as Ably from 'ably';¥n¥nimport { RoomReactionEvents } from './events.js';¥nimport { Logger } from './logger.js';¥nimport { Reaction, ReactionHeaders, ReactionMetadata } from './reaction.js';¥nimport { parseReaction } from './reaction-parser.js';¥nimport { messageToEphemeral } from './realtime.js';¥nimport { Subscription } from './subscription.js';¥nimport EventEmitter, { wrap } from './utils/event-emitter.js';¥n¥n/**¥n * Params for sending a room-level reactions. Only `type` is mandatory.¥n */¥nexport interface SendReactionParams {¥n  /**¥n   * The type of the reaction, for example an emoji or a short string such as¥n   * ¥"like¥".¥n   *¥n   * It is the only mandatory parameter to send a room-level reaction.¥n   */¥n  type: string;¥n¥n  /**¥n   * Optional metadata of the reaction.¥n   *¥n   * The metadata is a map of extra information that can be attached to the¥n   * room reaction. It is not used by Ably and is sent as part of