         state: this.channel.state,¥n        });¥n        throw new Ably.ErrorInfo('cannot type, room is not in the correct state', 50000, 500);¥n      }¥n¥n      // Check whether user is already typing before publishing again¥n      // CHA-T4c1, CHA-T4c2¥n      if (this._heartbeatTimerId) {¥n        this._logger.debug(`DefaultTyping.keystroke(); no-op, already typing and heartbeat timer has not expired`, {¥n          roomId: this._roomId,¥n        });¥n        return;¥n      }¥n¥n      // Perform the publish¥n      // CHA-T4a3¥n      await this._channel.publish(ephemeralMessage(TypingEventTypes.Start));¥n¥n      // Start the timer after publishing¥n      // CHA-T4a5¥n      this._startHeartbeatTimer();¥n      this._logger.trace(`DefaultTyping.keystroke(); starting timers`, { roomId: this._roomId });¥n    } finally {¥n      this._logger.trace(`DefaultTyping.keystroke(); releasing mutex`, { roomId: this._roomId });¥n      this._mutex.release();¥n    }¥n  }¥n¥n  /**¥n   * @inheritDoc¥n   */¥n  async stop(): Promise<void> {¥n    this._logger.trace(`DefaultTyping.stop();`, { roomId: this._roomId });¥n¥n    this._mutex.cancel();¥n    // Acquire a mutex¥n    await this._mutex.acquire().catch((error: unknown) => {¥n      if (error === E_CANCELED) {¥n        this._logger.debug(`DefaultTyping.stop(); mutex was canceled by a later operation`, { roomId: this._roomId });¥n        return;¥n      }¥n      throw new Ably.ErrorInfo('mutex acquisition failed', 50000, 500);¥n    });¥n    try {¥n      // CHA-T5c¥n      if (this.channel.state !== 'attached' && this.channel.state !== 'attaching') {¥n        this._logger.error(`DefaultTyping.stop(); room is not in the correct state `, {¥n          roomId: this._roomId,¥n          state: this.channel.state,¥n        });¥n        throw new Ably.ErrorInfo('cannot stop typing, room is not in the correct state', 50000, 500);¥n      }¥n¥n      // If the user is not typing, do nothing.¥n      // CHA-T5a¥n      if (!this._heartbeatTimerId) {¥n   