beat interval and the inactivity timeout.¥n   * @param clientId¥n   */¥n  private _startNewClientInactivityTimer(clientId: string): ReturnType<typeof setTimeout> {¥n    this._logger.trace(`DefaultTyping._startNewClientInactivityTimer(); starting new inactivity timer`, {¥n      roomId: this._roomId,¥n      clientId,¥n    });¥n    // Set or reset the typing timeout for this client¥n    const timeoutId = setTimeout(() => {¥n      this._logger.trace(`DefaultTyping._startNewClientInactivityTimer(); client typing timeout expired`, {¥n        roomId: this._roomId,¥n        clientId,¥n      });¥n      // Verify the timer is still valid (it might have been reset)¥n      if (this._currentlyTyping.get(clientId) !== timeoutId) {¥n        this._logger.debug(`DefaultTyping._startNewClientInactivityTimer(); timeout already cleared; ignoring`, {¥n          roomId: this._roomId,¥n          clientId,¥n        });¥n        return;¥n      }¥n¥n      // Remove client whose timeout has expired¥n      this._currentlyTyping.delete(clientId);¥n      this.emit(TypingSetEventTypes.SetChanged, {¥n        type: TypingSetEventTypes.SetChanged,¥n        currentlyTyping: new Set<string>(this._currentlyTyping.keys()),¥n        change: {¥n          clientId,¥n          type: TypingEventTypes.Stop,¥n        },¥n      });¥n    }, this._heartbeatThrottleMs + this._timeoutMs);¥n    return timeoutId;¥n  }¥n¥n  /**¥n   * Handles logic for TypingEventTypes.Start, including starting a new timeout or resetting an existing one.¥n   * @param clientId¥n   */¥n  private _handleTypingStart(clientId: string): void {¥n    this._logger.debug(`DefaultTyping._handleTypingStart();`, { roomId: this._roomId, clientId });¥n    // Start a new timeout for the client¥n    const timeoutId = this._startNewClientInactivityTimer(clientId);¥n¥n    const existingTimeout = this._currentlyTyping.get(clientId);¥n¥n    // Set the new timeout for the client¥n    this._currentlyTyping.set(clientId, timeoutId);¥n¥n    if (existingTimeout